package com.wherefood.repo;
import com.wherefood.domain.*; import org.springframework.data.jpa.repository.*; import org.springframework.data.repository.query.Param; import java.util.*;
public final class Repositories { private Repositories(){} public interface Users extends JpaRepository<User,Long>{ Optional<User> findByUsername(String username); } public interface Categories extends JpaRepository<Category,Long>{ List<Category> findByActiveTrueOrderByName(); } public interface Places extends JpaRepository<Place,Long>{@Override @EntityGraph(attributePaths={"category","createdBy"}) List<Place> findAll(); @EntityGraph(attributePaths={"category","createdBy"}) @Query("select p from Place p where p.id=:id") Optional<Place> findDetailedById(@Param("id") Long id);} public interface PlaceMetric{Long getPlaceId();Long getItemCount();Double getRating();} public interface Items extends JpaRepository<Item,Long>{@Override @EntityGraph(attributePaths={"author","place"}) Optional<Item> findById(Long id); @EntityGraph(attributePaths={"author"}) List<Item> findByPlaceIdOrderByIdDesc(Long placeId); @Query("select i.place.id as placeId, count(i) as itemCount, avg((i.taste+i.price+i.venue)/3.0) as rating from Item i where i.place.id in :ids group by i.place.id") List<PlaceMetric> metrics(@Param("ids") Collection<Long> ids);} public interface Photos extends JpaRepository<ItemPhoto,Long>{ Optional<ItemPhoto> findByItemId(Long id); List<ItemPhoto> findByItemIdIn(Collection<Long> ids); } }
